sect1.programlisting:
SELECT tquadbin '480fffffffffffff@2001-01-01';
SELECT tquadbin '{480fffffffffffff@2001-01-01, 48427fffffffffff@2001-01-02}';
SELECT tquadbin '[480fffffffffffff@2001-01-01, 48427fffffffffff@2001-01-02]';
SELECT tquadbin '{[480fffffffffffff@2001-01-01, 48427fffffffffff@2001-01-02],
  [48a6227affffffff@2001-01-03, 485623ffffffffff@2001-01-04]}';

SELECT tquadbin(Instant) '480fffffffffffff@2001-01-01';
SELECT tquadbin(SequenceSet) '{[480fffffffffffff@2001-01-01, 48427fffffffffff@2001-01-02]}';
-- ERROR: el tipo temporal (Instant) no coincide con el tipo de columna (Sequence)
SELECT tquadbin(Sequence) '480fffffffffffff@2001-01-01';

listitem.programlisting:
SELECT quadbin_is_valid_cell(quadbin '480fffffffffffff');
-- true
SELECT quadbin_is_valid_cell(quadbin '0');
-- false

SELECT valueN(tquadbin '{480fffffffffffff@2001-01-01, 48427fffffffffff@2001-01-02}', 1);
-- 480fffffffffffff
SELECT valueN(tquadbin '{480fffffffffffff@2001-01-01, 48427fffffffffff@2001-01-02}', 2);
-- 48427fffffffffff
SELECT valueN(tquadbin '480fffffffffffff@2001-01-01', 99);
-- NULL

SELECT quadbin_tile_to_cell(0, 0, 0) = quadbin '480fffffffffffff';
-- true
SELECT quadbin_tile_to_cell(3, 5, 4) = quadbin '48427fffffffffff';
-- true
SELECT quadbin_tile_to_cell(524, 343, 10) = quadbin '48a6227affffffff';
-- true

SELECT quadbin_cell_to_quadkey(quadbin '480fffffffffffff');
-- (cadena vacía)
SELECT quadbin_cell_to_quadkey(quadbin '48427fffffffffff');
-- 0213
SELECT quadbin_cell_to_quadkey(quadbin '48a6227affffffff');
-- 1202021322
